# Patch for small Python handler

def handle_request(request):
    try:
        # Existing logic
        response = process_request(request)
        return response
    except Exception as e:
        # Log error and return generic error message
        log_error(e)
        return "Internal Server Error"

def process_request(request):
    # Simulated request processing
    if 'data' not in request:
        raise ValueError("Missing data")
    return f"Processed: {request['data']}"

def log_error(error):
    # Simple logging function
    print(f"Error: {error}")

# Regression tests

def test_handle_request_with_valid_data():
    assert handle_request({'data': 'test'}) == "Processed: test"

def test_handle_request_without_data():
    assert handle_request({}) == "Internal Server Error"
```

